mapper.select:
SELECT cr.*, c.category_name AS categoryName, i.file_path AS imagePath FROM cultural_relic cr LEFT JOIN cultural_relic_category c ON cr.category_id = c.id LEFT JOIN relic_image_relation rir ON cr.id = rir.relic_id LEFT JOIN image_library i ON rir.image_id = i.id AND i.status = 1
AND cr.relic_name LIKE CONCAT('%', #{relicName}, '%')
AND cr.category_id = #{categoryId}
AND cr.status = #{status}
AND cr.era LIKE CONCAT('%', #{era}, '%')
ORDER BY cr.id ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM cultural_relic cr


        AND cr.relic_name LIKE CONCAT('%', #{relicName}, '%')


        AND cr.category_id = #{categoryId}


        AND cr.status = #{status}


        AND cr.era LIKE CONCAT('%', #{era}, '%')

SELECT COUNT(1)
FROM cultural_relic
WHERE YEAR(create_time) = #{year}
AND MONTH(create_time) = #{month}

SELECT COUNT(1)
FROM cultural_relic
WHERE DATE(create_time) BETWEEN #{startDate} AND #{endDate}

