relic_code = #{relicCode}, relic_name = #{relicName}, category_id = #{categoryId}, era = #{era}, material = #{material}, origin = #{origin}, dimensions = #{dimensions}, weight = #{weight}, description = #{description}, status = #{status}, image_path = #{imagePath}, update_time = #{updateTime},
